import { useEffect, useState } from 'react';
import { getTasks, updateTask, deleteTask } from './services/api';

export default function TaskList() {
  const [tasks, setTasks] = useState([]);

  // Load tasks on mount
  useEffect(() => {
    getTasks().then(res => {
      // NOTE: If your backend returns the array directly, just use 'res'
      // If your backend wraps it, you might need res.data
      setTasks(res); 
    });
  }, []);

  // 🗑️ FIX FOR DELETE BUTTON
  const handleDelete = async (taskToDelete) => {
    try {
      // CRITICAL: Must pass ._id, NOT .id
      await deleteTask(taskToDelete._id); 
      
      // Update local state so it disappears from the screen immediately
      setTasks(prev => prev.filter(t => t._id !== taskToDelete._id));
    } catch (err) {
      console.error("Failed to delete task:", err);
    }
  };

  // ⚙️ FIX FOR "IN PROGRESS" BUTTON
  const handleSetInProgress = async (taskToUpdate) => {
    try {
      // CRITICAL: Pass the ._id and the updated status payload
      const updatedData = await updateTask(taskToUpdate._id, { status: "in progress" });
      
      // Update local state so the badge/UI changes color
      setTasks(prev => 
        prev.map(t => t._id === taskToUpdate._id ? { ...t, status: "in progress" } : t)
      );
    } catch (err) {
      console.error("Failed to update status:", err);
    }
  };

  return (
    <div>
      {tasks.map(task => (
        <div key={task._id} className="task-card">
          <h3>{task.title}</h3>
          <p>Status: {task.status}</p>
          
          {/* Status Button */}
          <button onClick={() => handleSetInProgress(task)}>
            Work on This
          </button>
          
          {/* Delete Button */}
          <button onClick={() => handleDelete(task)}>
            Delete
          </button>
        </div>
      ))}
    </div>
  );
}
